import{_ as t,o as a,c as o,aQ as s}from"./chunks/framework.cDvftfeu.js";const p=JSON.parse('{"title":"About","description":"About Ham, security, privacy, and open-source status.","frontmatter":{"description":"About Ham, security, privacy, and open-source status."},"headers":[],"relativePath":"en/about/index.md","filePath":"en/about/index.md","lastUpdated":1777525243000}'),i={name:"en/about/index.md"};function n(r,e,u,d,c,h){return a(),o("div",null,[...e[0]||(e[0]=[s('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /about.md for this page in Markdown format</div><h1 id="about" tabindex="-1">About <a class="header-anchor" href="#about" aria-label="Permalink to &quot;About&quot;">​</a></h1><h3 id="is-ham-safe" tabindex="-1">Is Ham safe? <a class="header-anchor" href="#is-ham-safe" aria-label="Permalink to &quot;Is Ham safe?&quot;">​</a></h3><p>Ham does not send your student account and password to a third-party server for validation. Your account data is stored locally, and your phone connects directly to the university servers.</p><p>Some features (like grade distribution) require a backend service. When data must be sent, it is only sent with your consent. Sensitive identifiers (such as student ID) are hashed before transmission, so we cannot identify individual users.</p><h3 id="why-is-it-not-open-source-yet" tabindex="-1">Why is it not open source (yet)? <a class="header-anchor" href="#why-is-it-not-open-source-yet" aria-label="Permalink to &quot;Why is it not open source (yet)?&quot;">​</a></h3><p>The project includes private credentials (push services, Apple developer account, etc.), so it is not open source for now. Ham is still completely free to use.</p><p>If you have suggestions, feel free to reach out on <a href="https://github.com/whu-ham/whu-ham.github.io/discussions" target="_blank" rel="noreferrer">GitHub Discussions</a>. Technical discussions are welcome too.</p>',8)])])}const m